code = """import json, pandas as pd

def clean_id(x):
    if x is None:
        return None
    return str(x).strip().lstrip('#')

cases = pd.DataFrame(var_call_RIsiDbG3hdY0xg3RLvHqaoDv)
accts = pd.DataFrame(var_call_kfIwBEwY57rvo9cfyQSpXr0r)

if not cases.empty:
    cases['account_id_clean'] = cases['account_id_clean'].map(clean_id)
    cases['closure_days'] = pd.to_numeric(cases['closure_days'], errors='coerce')

if not accts.empty:
    accts['account_id_clean'] = accts['account_id_raw'].map(clean_id)
    accts['ShippingState'] = accts['ShippingState'].astype(str).str.strip()

merged = cases.merge(accts[['account_id_clean','ShippingState']], on='account_id_clean', how='left')
merged = merged.dropna(subset=['ShippingState','closure_days'])

# compute average closure time by state
state_stats = (merged.groupby('ShippingState', as_index=False)
               .agg(avg_closure_days=('closure_days','mean'), case_count=('case_id','count')))

# pick state with minimum avg closure days; tie-breaker: more cases, then alphabetical
state_stats = state_stats.sort_values(['avg_closure_days','case_count','ShippingState'], ascending=[True, False, True])
answer = state_stats.iloc[0]['ShippingState'] if len(state_stats) else None

print('__RESULT__:')
print(json.dumps({'state': answer}))"""

